text:
{
  "formal_minutes": {
    "decisions": {
      "confirmed_decisions": [
        "공개 릴리스 목표는 스모크 테스트 통과 시 `금요일 15:00 KST`로 확정한다.",
        "packageName 불일치가 발생하면 `smoke-theme-pack.mjs`를 무시하지 않고 먼저 패키지 설정값을 점검하며, 계약 자체가 잘못된 경우에만 스크립트 검토를 추진한다."
      ],
      "non_decisions": [
        "README 설치 단계는 목요일 안으로(가능하면) 리뷰해야 한다는 제안이 있었으나, 실제 담당자와 고정 마감시간은 확정되지 않았다.",
        "Hara는 Minjun 결과 공유 후 tarball 경로 확인을 진행하되, 완료 기한은 정해지지 않았다."
      ]
    },
    "rejected_proposals": [
      "Hara의 `smoke-theme-pack.mjs`에서 packageName mismatch를 무시하도록 변경하자는 제안은 최종 반려됨."
    ],
    "internal_stretch_goals": [
      "수요일 공개는 내부 stretch goal로만 언급되었고, 공식 릴리스 목표로 채택되지 않았다."
    ],
    "risks": [
      "생성된 tarball 경로 오류 시 릴리스가 지연될 수 있음.",
      "README 설치 단계가 오래되면 릴리스 노트/안내가 사용자에게 오해를 줄 수 있음."
    ],
    "open_questions": [
      "최종 릴리스 승인 권한자는 누구인가?",
      "내부 stretch goal인 수요일 일정을 릴리스 노트에 기재해야 하는지 여부는 미결정."
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 재실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "높음"
    },
    {
      "owner": "Doyun",
      "task": "실패 트리아지 노트를 `action_items.md`에 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "확정",
      "source_certainty": "높음"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 스모크 테스트 결과를 게시한 뒤 생성된 tarball 경로를 확인한다.",
      "due": "명시적 기한 없음(결과 게시 후 즉시)",
      "status": "진행예정",
      "source_certainty": "높음"
    },
    {
      "owner": "미지정",
      "task": "README 설치 단계 리뷰를 수행한다(요청만 존재).",
      "due": "목표: 목요일(가능 시)",
      "status": "미확정",
      "source_certainty": "중간"
    }
  ],
  "followup_note": {
    "what_to_check_next": [
      "금요일 10:00 KST 이전에 Minjun의 스모크 테스트 결과 공유 여부",
      "스모크 통과 전제 하에 금요일 15:00 KST 공개 릴리스 실행 조건 충족 여부",
      "Doyun의 실패 트리아지 노트 제출 여부 및 저장 위치(`action_items.md`)",
      "Hara의 tarball 경로 점검 결과(경로 오류 유무)",
      "README 설치 단계 리뷰 담당자와 실제 완료 여부"
    ],
    "what_not_to_invent": [
      "고객명/외부 파트너",
      "예산",
      "보안 관련 사실",
      "운영 장애 이력",
      "법무 승인 필요성",
      "확정되지 않은 owner",
      "확정되지 않은 deadline"
    ]
  },
  "non_invention_rules": [
    "팩트가 명시되지 않은 항목(고객, 예산, 보안, 장애, 법무, owner, deadline)은 절대 생성하지 않는다.",
    "수요일 공개 제안은 내부 stretch goal로만 분리해 표기하고, 공개 릴리스 결정사항(금요일 15:00 KST)과 혼동하지 않는다.",
    "반려된 제안과 승인된 결정을 구분한다.",
    "오픈 질문은 ‘해결됨’으로 바꾸지 않고 그대로 미결 상태로 남긴다."
  ]
}
